#include <bits/stdc++.h>
using namespace std;
int n,m,a[102][11],step[1<<10];
int pres(int x,int y){
    for(int i=1;i<=n;i++){
        if(a[y][i]==1)
            x&=(1<<n)-1-(1<<i-1);
        else if(a[y][i]==-1)
            x|=1<<i-1;
    }
    return x;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
        for(int j=1;j<=n;j++)
            scanf("%d",&a[i][j]);
    queue<int> b;
    b.push((1<<n)-1);
    step[(1<<n)-1]=1;
    while(b.size()){
        int u=b.front();
        b.pop();
        for(int i=1;i<=m;i++)
            if(!step[pres(u,i)])
                step[pres(u,i)]=step[u]+1,b.push(pres(u,i));
    }
    printf("%d",step[0]-1);
    return 0;
}
